{"content":"1: syntax = "proto3";
2: 
3: package envoy;
4: 
5: message HotRestartMessage {
6:   // Child->parent requests
7:   message Request {
8:     message PassListenSocket {
9:       string address = 1;
10:       uint32 worker_index = 2;
11:     }
12:     message ShutdownAdmin {
13:     }
14:     message Stats {
15:     }
16:     message DrainListeners {
17:     }
18:     message Terminate {
19:     }
20:     // A separate socket is established for forwarding undeliverable quic udp packets
21:     // from the parent instance to the child instance.
22:     message ForwardedUdpPacket {
23:       string local_addr = 1;
24:       string peer_addr = 2;
25:       uint64 receive_time_epoch_microseconds = 3;
26:       bytes payload = 4;
27:       uint32 worker_index = 5;
28:     }
29:     message TestConnection {
30:     }
31:     oneof request {
32:       PassListenSocket pass_listen_socket = 1;
33:       ShutdownAdmin shutdown_admin = 2;
34:       Stats stats = 3;
35:       DrainListeners drain_listeners = 4;
36:       Terminate terminate = 5;
37:       ForwardedUdpPacket forwarded_udp_packet = 6;
38:       TestConnection test_connection = 7;
39:     }
40:   }
41: 
42:   // Parent->child replies
43:   message Reply {
44:     message PassListenSocket {
45:       int32 fd = 1;
46:     }
47:     message ShutdownAdmin {
48:       uint64 original_start_time_unix_seconds = 1;
49:       // See the comments on Server::Instance::enableReusePortDefault() for why this exists. The
50:       // default is false for backwards compatibility.
51:       bool enable_reuse_port_default = 2;
52:     }
53:     message Span {
54:       uint32 first = 1;
55:       uint32 last = 2; // inclusive
56:     }
57:     message RepeatedSpan {
58:       repeated Span spans = 1;
59:     }
60:     message Stats {
61:       // Values for server_stats, which don't fit with the "combination logic" approach.
62:       uint64 memory_allocated = 1;
63:       uint64 num_connections = 2;
64: 
65:       // Keys are fully qualified stat names.
66:       //
67:       // The amount added to the counter since the last time a message included the counter in this
68:       // map. (The first time a counter is included in this map, it's the amount added since the
69:       // final latch() before hot restart began).
70:       map<string, uint64> counter_deltas = 3;
71:       // The parent's current values for various gauges in its stats store.
72:       map<string, uint64> gauges = 4;
73:       // Maps the string representation of a StatName into an array of Spans,
74:       // which indicate which of the StatName tokens are dynamic. For example,
75:       // if we are recording a counter or gauge named "a.b.c.d.e.f", where "a",
76:       // and "d.e" were created from a StatNameDynamicPool, then we'd map
77:       // "a.b.c.d.e.f" to the span array [[0,0], [3,4]], where the [0,0] span
78:       // covers the "a", and the [3,4] span covers "d.e".
79:       map<string, RepeatedSpan> dynamics = 5;
80:     }
81:     oneof reply {
82:       // When this oneof is of the PassListenSocketReply type, there is a special
83:       // implied meaning: the recvmsg that got this proto has control data to make
84:       // the passing of the fd work, so make use of CMSG_SPACE etc.
85:       PassListenSocket pass_listen_socket = 1;
86:       ShutdownAdmin shutdown_admin = 2;
87:       Stats stats = 3;
88:     }
89:   }
90: 
91:   oneof requestreply {
92:     Request request = 1;
93:     Reply reply = 2;
94:   }
95: 
96:   bool didnt_recognize_your_last_message = 3;
97: }
