53:   void onSocketEvent();
54: 
55:   const int restart_epoch_;
56:   sockaddr_un child_address_;
57:   sockaddr_un child_address_udp_forwarding_;
58:   Event::FileEventPtr socket_event_;
59:   OptRef<Event::Dispatcher> dispatcher_;
60:   std::unique_ptr<Internal> internal_;
61: };
