20:   class UdpForwardingContext {
21:   public:
22:     using ForwardEntry = std::pair<Network::Address::InstanceConstSharedPtr,
23:                                    std::shared_ptr<Network::UdpListenerConfig>>;
24: 
25:     // Returns the address and UdpListenerConfig associated with the given address.
26:     // The addresses are not necessarily identical, as e.g. the listener might be listening on
27:     // 0.0.0.0.
