36:     // This is called from the main thread during listening socket creation.
37:     void registerListener(Network::Address::InstanceConstSharedPtr address,
38:                           std::shared_ptr<Network::UdpListenerConfig> listener_config);
39: 
40:   private:
41:     // Map keyed on address as a string, because Network::Address::Instance isn't hashable.
42:     absl::flat_hash_map<std::string, ForwardEntry> listener_map_;
43:   };
