72: private:
73:   bool abortDueToFailedParentConnection();
74:   friend class HotRestartUdpForwardingTestHelper;
75:   absl::Mutex registry_mu_;
76:   const int restart_epoch_;
77:   bool parent_terminated_;
78:   bool parent_drained_ ABSL_GUARDED_BY(registry_mu_);
79:   const bool skip_hot_restart_on_no_parent_;
