26: SharedMemory* attachSharedMemory(uint32_t base_id, uint32_t restart_epoch) {
27:   Api::OsSysCalls& os_sys_calls = Api::OsSysCallsSingleton::get();
28:   Api::HotRestartOsSysCalls& hot_restart_os_sys_calls = Api::HotRestartOsSysCallsSingleton::get();
29: 
30:   int flags = O_RDWR;
31:   const std::string shmem_name = fmt::format("/envoy_shared_memory_{}", base_id);
32:   if (restart_epoch == 0) {
33:     flags |= O_CREAT | O_EXCL;
34: 
35:     // If we are meant to be first, attempt to unlink a previous shared memory instance. If this
36:     // is a clean restart this should then allow the shm_open() call below to succeed.
37:     hot_restart_os_sys_calls.shmUnlink(shmem_name.c_str());
38:   }
39: 
40:   const Api::SysCallIntResult result =
41:       hot_restart_os_sys_calls.shmOpen(shmem_name.c_str(), flags, S_IRUSR | S_IWUSR);
42:   if (result.return_value_ == -1) {
43:     PANIC(fmt::format("cannot open shared memory region {} check user permissions. Error: {}",
44:                       shmem_name, errorDetails(result.errno_)));
45:   }
46: 
47:   if (restart_epoch == 0) {
48:     const Api::SysCallIntResult truncateRes =
49:         os_sys_calls.ftruncate(result.return_value_, sizeof(SharedMemory));
50:     RELEASE_ASSERT(truncateRes.return_value_ != -1, "");
51:   }
52: 
53:   const Api::SysCallPtrResult mmapRes = os_sys_calls.mmap(
54:       nullptr, sizeof(SharedMemory), PROT_READ | PROT_WRITE, MAP_SHARED, result.return_value_, 0);
55:   SharedMemory* shmem = reinterpret_cast<SharedMemory*>(mmapRes.return_value_);
56:   RELEASE_ASSERT(shmem != MAP_FAILED, "");
57:   RELEASE_ASSERT((reinterpret_cast<uintptr_t>(shmem) % alignof(decltype(shmem))) == 0, "");
58: 
59:   if (restart_epoch == 0) {
60:     shmem->size_ = sizeof(SharedMemory);
61:     shmem->version_ = HOT_RESTART_VERSION;
62:     initializeMutex(shmem->log_lock_);
63:     initializeMutex(shmem->access_log_lock_);
64:   } else {
65:     RELEASE_ASSERT(shmem->size_ == sizeof(SharedMemory),
66:                    "Hot restart SharedMemory size mismatch! You must have hot restarted into a "
67:                    "not-hot-restart-compatible new version of Envoy.");
68:     RELEASE_ASSERT(shmem->version_ == HOT_RESTART_VERSION,
69:                    "Hot restart version mismatch! You must have hot restarted into a "
70:                    "not-hot-restart-compatible new version of Envoy.");
71:   }
72: 
73:   // Here we catch the case where a new Envoy starts up when the current Envoy has not yet fully
74:   // initialized. The startup logic is quite complicated, and it's not worth trying to handle this
75:   // in a finer way. This will cause the startup to fail with an error code early, without
76:   // affecting any currently running processes. The process runner should try again later with some
77:   // back off and with the same hot restart epoch number.
78:   uint64_t old_flags = shmem->flags_.fetch_or(SHMEM_FLAGS_INITIALIZING);
79:   if (old_flags & SHMEM_FLAGS_INITIALIZING) {
80:     throw EnvoyException("previous envoy process is still initializing");
81:   }
82:   return shmem;
83: }
84: 
85: void initializeMutex(pthread_mutex_t& mutex) {
86:   pthread_mutexattr_t attribute;
87:   pthread_mutexattr_init(&attribute);
88:   pthread_mutexattr_setpshared(&attribute, PTHREAD_PROCESS_SHARED);
89:   pthread_mutexattr_setrobust(&attribute, PTHREAD_MUTEX_ROBUST);
90:   pthread_mutex_init(&mutex, &attribute);
91: }
92: 
93: // The base id is automatically scaled by 10 to prevent overlap of domain socket names when
94: // multiple Envoys with different base-ids run on a single host. Note that older versions of Envoy
95: // performed the multiplication in OptionsImpl which produced incorrect server info output.
96: // TODO(zuercher): ideally, the base_id would be separated from the restart_epoch in
97: // the socket names to entirely prevent collisions between consecutive base ids.
98: HotRestartImpl::HotRestartImpl(uint32_t base_id, uint32_t restart_epoch,
99:                                const std::string& socket_path, mode_t socket_mode,
100:                                bool skip_hot_restart_on_no_parent, bool skip_parent_stats)
101:     : base_id_(base_id), scaled_base_id_(base_id * 10),
102:       as_child_(HotRestartingChild(scaled_base_id_, restart_epoch, socket_path, socket_mode,
103:                                    skip_hot_restart_on_no_parent, skip_parent_stats)),
104:       as_parent_(HotRestartingParent(scaled_base_id_, restart_epoch, socket_path, socket_mode)),
105:       shmem_(attachSharedMemory(scaled_base_id_, restart_epoch)), log_lock_(shmem_->log_lock_),
106:       access_log_lock_(shmem_->access_log_lock_) {
107:   // If our parent ever goes away just terminate us so that we don't have to rely on ops/launching
108:   // logic killing the entire process tree. We should never exist without our parent.
109:   int rc = prctl(PR_SET_PDEATHSIG, SIGTERM);
110:   RELEASE_ASSERT(rc != -1, "");
111: }
112: 
113: void HotRestartImpl::drainParentListeners() {
114:   as_child_.drainParentListeners();
115:   // At this point we are initialized and a new Envoy can startup if needed.
116:   shmem_->flags_ &= ~SHMEM_FLAGS_INITIALIZING;
117: }
