144: HotRestart::ServerStatsFromParent
145: HotRestartImpl::mergeParentStatsIfAny(Stats::StoreRoot& stats_store) {
146:   std::unique_ptr<envoy::HotRestartMessage> wrapper_msg = as_child_.getParentStats();
147:   ServerStatsFromParent response;
148:   // getParentStats() will happily and cleanly return nullptr if we have no parent.
149:   if (wrapper_msg) {
150:     as_child_.mergeParentStats(stats_store, wrapper_msg->reply().stats());
151:     response.parent_memory_allocated_ = wrapper_msg->reply().stats().memory_allocated();
152:     response.parent_connections_ = wrapper_msg->reply().stats().num_connections();
153:   }
154:   return response;
155: }
