165: bool HotRestartImpl::isInitializing() const {
166:   return (shmem_->flags_.load() & SHMEM_FLAGS_INITIALIZING) != 0;
167: }
168: 
169: std::string HotRestartImpl::hotRestartVersion() {
170:   return fmt::format("{}.{}", HOT_RESTART_VERSION, sizeof(SharedMemory));
171: }
