32: sockaddr_un RpcStream::createDomainSocketAddress(uint64_t id, const std::string& role,
33:                                                  const std::string& socket_path,
34:                                                  mode_t socket_mode) {
35:   // Right now we only allow a maximum of 3 concurrent envoy processes to be running. When the third
36:   // starts up it will kill the oldest parent.
37:   static constexpr uint64_t MaxConcurrentProcesses = 3;
38:   id = id % MaxConcurrentProcesses;
