37: void HotRestartingParent::Internal::handle(uint32_t worker_index,
38:                                            const Network::UdpRecvData& packet) {
39:   envoy::HotRestartMessage msg;
40:   auto* packet_msg = msg.mutable_request()->mutable_forwarded_udp_packet();
41:   packet_msg->set_local_addr(Network::Utility::urlFromDatagramAddress(*packet.addresses_.local_));
42:   packet_msg->set_peer_addr(Network::Utility::urlFromDatagramAddress(*packet.addresses_.peer_));
43:   packet_msg->set_receive_time_epoch_microseconds(
44:       std::chrono::duration_cast<std::chrono::microseconds>(packet.receive_time_.time_since_epoch())
45:           .count());
