51: void HotRestartingParent::initialize(Event::Dispatcher& dispatcher, Server::Instance& server) {
52:   socket_event_ = dispatcher.createFileEvent(
53:       main_rpc_stream_.domain_socket_,
54:       [this](uint32_t events) {
55:         ASSERT(events == Event::FileReadyType::Read);
56:         onSocketEvent();
57:         return absl::OkStatus();
58:       },
59:       Event::FileTriggerType::Edge, Event::FileReadyType::Read);
60:   dispatcher_ = dispatcher;
61:   internal_ = std::make_unique<Internal>(&server, *this);
