64: void HotRestartingParent::onSocketEvent() {
65:   std::unique_ptr<HotRestartMessage> wrapped_request;
66:   while ((wrapped_request = main_rpc_stream_.receiveHotRestartMessage(RpcStream::Blocking::No))) {
67:     if (wrapped_request->requestreply_case() == HotRestartMessage::kReply) {
68:       ENVOY_LOG(error, "child sent us a HotRestartMessage reply (we want requests); ignoring.");
69:       HotRestartMessage wrapped_reply;
70:       wrapped_reply.set_didnt_recognize_your_last_message(true);
71:       main_rpc_stream_.sendHotRestartMessage(child_address_, wrapped_reply);
72:       continue;
73:     }
74:     switch (wrapped_request->request().request_case()) {
75:     case HotRestartMessage::Request::kShutdownAdmin: {
76:       main_rpc_stream_.sendHotRestartMessage(child_address_, internal_->shutdownAdmin());
77:       break;
78:     }
79: 
80:     case HotRestartMessage::Request::kPassListenSocket: {
81:       main_rpc_stream_.sendHotRestartMessage(
82:           child_address_, internal_->getListenSocketsForChild(wrapped_request->request()));
83:       break;
84:     }
85: 
86:     case HotRestartMessage::Request::kStats: {
87:       HotRestartMessage wrapped_reply;
88:       internal_->exportStatsToChild(wrapped_reply.mutable_reply()->mutable_stats());
89:       main_rpc_stream_.sendHotRestartMessage(child_address_, wrapped_reply);
90:       break;
91:     }
92: 
93:     case HotRestartMessage::Request::kDrainListeners: {
94:       internal_->drainListeners();
95:       break;
96:     }
97: 
98:     case HotRestartMessage::Request::kTerminate: {
99:       ENVOY_LOG(info, "shutting down due to child request");
100:       kill(getpid(), SIGTERM);
101:       break;
102:     }
103: 
104:     case HotRestartMessage::Request::kTestConnection: {
105:       break;
106:     }
107: 
108:     default: {
109:       ENVOY_LOG(error, "child sent us an unfamiliar type of HotRestartMessage; ignoring.");
110:       HotRestartMessage wrapped_reply;
111:       wrapped_reply.set_didnt_recognize_your_last_message(true);
112:       main_rpc_stream_.sendHotRestartMessage(child_address_, wrapped_reply);
113:       break;
114:     }
115:     }
116:   }
117: }
