12: void HotRestartingChild::UdpForwardingContext::registerListener(
13:     Network::Address::InstanceConstSharedPtr address,
14:     std::shared_ptr<Network::UdpListenerConfig> listener_config) {
15:   const bool inserted =
16:       listener_map_.try_emplace(address->asString(), ForwardEntry{address, listener_config}).second;
17:   ASSERT(inserted, "Two udp listeners on the same address shouldn't be possible");
18: }
