49: // If restart_epoch is 0 there is no parent, so it's effectively already
50: // drained and terminated.
51: HotRestartingChild::HotRestartingChild(int base_id, int restart_epoch,
52:                                        const std::string& socket_path, mode_t socket_mode,
53:                                        bool skip_hot_restart_on_no_parent, bool skip_parent_stats)
54:     : HotRestartingBase(base_id), restart_epoch_(restart_epoch),
55:       parent_terminated_(restart_epoch == 0), parent_drained_(restart_epoch == 0),
56:       skip_hot_restart_on_no_parent_(skip_hot_restart_on_no_parent),
57:       skip_parent_stats_(skip_parent_stats) {
58:   main_rpc_stream_.initDomainSocketAddress(&parent_address_);
59:   std::string socket_path_udp = socket_path + "_udp";
60:   udp_forwarding_rpc_stream_.initDomainSocketAddress(&parent_address_udp_forwarding_);
61:   if (restart_epoch_ != 0) {
62:     parent_address_ = main_rpc_stream_.createDomainSocketAddress(restart_epoch_ + -1, "parent",
63:                                                                  socket_path, socket_mode);
64:     parent_address_udp_forwarding_ = udp_forwarding_rpc_stream_.createDomainSocketAddress(
65:         restart_epoch_ + -1, "parent", socket_path_udp, socket_mode);
66:   }
67:   main_rpc_stream_.bindDomainSocket(restart_epoch_, "child", socket_path, socket_mode);
68:   udp_forwarding_rpc_stream_.bindDomainSocket(restart_epoch_, "child", socket_path_udp,
69:                                               socket_mode);
70: }
