84: void HotRestartingChild::initialize(Event::Dispatcher& dispatcher) {
85:   if (abortDueToFailedParentConnection()) {
86:     ENVOY_LOG(warn, "hot restart sendmsg() connection refused, falling back to regular restart");
87:     absl::MutexLock lock(registry_mu_);
88:     parent_terminated_ = parent_drained_ = true;
89:     return;
90:   }
91:   socket_event_udp_forwarding_ = dispatcher.createFileEvent(
92:       udp_forwarding_rpc_stream_.domain_socket_,
93:       [this](uint32_t events) {
94:         ASSERT(events == Event::FileReadyType::Read);
95:         return onSocketEventUdpForwarding();
96:       },
97:       Event::FileTriggerType::Edge, Event::FileReadyType::Read);
98: }
