127: int HotRestartingChild::duplicateParentListenSocket(const std::string& address,
128:                                                     uint32_t worker_index) {
129:   if (parent_terminated_) {
130:     return -1;
131:   }
132: 
133:   HotRestartMessage wrapped_request;
134:   wrapped_request.mutable_request()->mutable_pass_listen_socket()->set_address(address);
135:   wrapped_request.mutable_request()->mutable_pass_listen_socket()->set_worker_index(worker_index);
136:   main_rpc_stream_.sendHotRestartMessage(parent_address_, wrapped_request);
137: 
138:   std::unique_ptr<HotRestartMessage> wrapped_reply =
139:       main_rpc_stream_.receiveHotRestartMessage(RpcStream::Blocking::Yes);
140:   if (!main_rpc_stream_.replyIsExpectedType(wrapped_reply.get(),
141:                                             HotRestartMessage::Reply::kPassListenSocket)) {
142:     return -1;
143:   }
144:   return wrapped_reply->reply().pass_listen_socket().fd();
145: }
