147: std::unique_ptr<HotRestartMessage> HotRestartingChild::getParentStats() {
148:   if (parent_terminated_ || skip_parent_stats_) {
149:     return nullptr;
150:   }
151: 
152:   HotRestartMessage wrapped_request;
153:   wrapped_request.mutable_request()->mutable_stats();
154:   main_rpc_stream_.sendHotRestartMessage(parent_address_, wrapped_request);
155: 
156:   std::unique_ptr<HotRestartMessage> wrapped_reply =
157:       main_rpc_stream_.receiveHotRestartMessage(RpcStream::Blocking::Yes);
158:   RELEASE_ASSERT(
159:       main_rpc_stream_.replyIsExpectedType(wrapped_reply.get(), HotRestartMessage::Reply::kStats),
160:       "Hot restart parent did not respond as expected to get stats request.");
161:   return wrapped_reply;
162: }
