164: void HotRestartingChild::drainParentListeners() {
165:   if (parent_terminated_) {
166:     return;
167:   }
168:   // No reply expected.
169:   HotRestartMessage wrapped_request;
170:   wrapped_request.mutable_request()->mutable_drain_listeners();
171:   main_rpc_stream_.sendHotRestartMessage(parent_address_, wrapped_request);
172: }
