174: void HotRestartingChild::registerUdpForwardingListener(
175:     Network::Address::InstanceConstSharedPtr address,
176:     std::shared_ptr<Network::UdpListenerConfig> listener_config) {
177:   ASSERT_IS_MAIN_OR_TEST_THREAD();
178:   udp_forwarding_context_.registerListener(address, listener_config);
179: }
180: 
181: void HotRestartingChild::registerParentDrainedCallback(
182:     const Network::Address::InstanceConstSharedPtr& address, absl::AnyInvocable<void()> callback) {
183:   absl::MutexLock lock(registry_mu_);
184:   if (parent_drained_) {
185:     callback();
186:   } else {
187:     on_drained_actions_.emplace(address->asString(), std::move(callback));
188:   }
189: }
190: 
191: void HotRestartingChild::allDrainsImplicitlyComplete() {
192:   absl::MutexLock lock(registry_mu_);
193:   for (auto& drain_action : on_drained_actions_) {
194:     // Call the callback.
195:     std::move(drain_action.second)();
196:   }
197:   on_drained_actions_.clear();
198:   parent_drained_ = true;
199: }
