187:       // latching) by the time it begins exporting to the hot restart child.
188:       uint64_t latched_value = counter.latch();
189:       if (latched_value > 0) {
190:         const std::string name = counter.name();
191:         (*stats->mutable_counter_deltas())[name] = latched_value;
192:         recordDynamics(stats, name, counter.statName());
